import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e}from"./app-0f4fe9af.js";const t={},p=e(`<h1 id="上下文" tabindex="-1"><a class="header-anchor" href="#上下文" aria-hidden="true">#</a> 上下文</h1><blockquote><p>上下文：即语境，语意，在程序中可以理解为在代码执行到某个时刻，根据之前代码锁做的操作以及下文即将要执行的逻辑，可以决定在当前时刻下可以使用到的变量，或者可以做的事情。</p></blockquote><h2 id="上下文对象" tabindex="-1"><a class="header-anchor" href="#上下文对象" aria-hidden="true">#</a> 上下文对象</h2><p>Flask中有两种上下文：<code>请求上下文（request context）</code>和<code>应用上下文（application context）</code>。</p><p>Flask中上下文对象：相当于一个容器，保存了Flask程序运行过程中的一些信息。</p><h3 id="requestcontext" tabindex="-1"><a class="header-anchor" href="#requestcontext" aria-hidden="true">#</a> <code>RequestContext</code></h3><p>在<em>Flask</em>中，可以直接在视图函数中使用<code>request</code>这个独享进行获取相关数据，而<code>request</code>就是请求上下文对象，保存了本次请求的相关数据。<strong>请求上下文对象有：<strong>​</strong><code>request</code><strong>​</strong>、<strong>​</strong><code>session</code></strong></p><h4 id="request" tabindex="-1"><a class="header-anchor" href="#request" aria-hidden="true">#</a> <code>Request</code></h4><p><code>Request</code> 请求的对象。封装了<em>HTTP</em>请求的内容，针对的是<em>http</em>请求。</p><p><strong>flask在每个请求产生后自动激活当前请求的上下文，激活请求上下文后，request被临时设为全局可访问</strong>。当每个请求结束后，flask就销毁对应的请求上下文。</p><p>在前面说request是全局对象，但这里的全局并不是实际意义上的全局。我们把这些变量理解为动态的全局变量。</p><p>在多线程服务中，在同一时间可能会有多个请求在处理。假设有三个客户端同时向服务器发送请求，这时每个请求都有各自不同的请求报文，所以请求对象必然是不同的。</p><p>因此，请求对象只在各自的线程内是全局的。flask通过本地线程（thread local）技术将请求对象在特定的线程和请求中全局可访问。</p><p>例如：</p><ul><li><code>user = request.args.get(&#39;user&#39;)</code>，获取的是<em>get</em>请求的参数。</li></ul><h4 id="session" tabindex="-1"><a class="header-anchor" href="#session" aria-hidden="true">#</a> <code>Session</code></h4><p><code>Session</code> 根据请求中的<em>cookie</em>，重新载入该访问者相关的会话信息，针对的是用户信息。例如：</p><ul><li><code>session[&#39;name&#39;] = user.id</code> 可以记录用户信息。</li><li><code>session.get(&#39;name&#39;)</code>可以获取用户信息。</li></ul><h3 id="applicationcontext" tabindex="-1"><a class="header-anchor" href="#applicationcontext" aria-hidden="true">#</a> <code>ApplicationContext</code></h3><p>它不是一直存在的，它只是<em>request context</em>中的一个对<em>app</em>的代理，所谓的<em>local proxy</em>。它的作用主要是帮助<em>request</em>获取当前的应用，它是伴<em>request</em>而生，随<em>request</em>而灭的。<strong>应用上下文对象有：<strong>​</strong><code>current_app</code><strong>​</strong>,<strong>​</strong><code>g</code></strong></p><h4 id="current-app" tabindex="-1"><a class="header-anchor" href="#current-app" aria-hidden="true">#</a> <code>current_app</code></h4><p><code>current_app</code> 当前激活程序的程序实例。程序会有多个程序实例的情况，为了能获取对应的程序实例，而不是固定的某一个程序实例，我们就需要使用<code>current_app</code>变量。</p><p>用于存储应用程序中的变量，可以通过<code>current_app.name</code>打印当前<em>app</em>的名称，也可以在<code>current_app</code>中存储一些变量，例如：</p><ul><li>应用的启动脚本是哪个文件，启动时指定了哪些参数</li><li>加载了哪些配置文件，导入了哪些配置</li><li>连接了哪个数据库</li><li>有哪些可以调用的工具类、常量</li><li>当前flask应用在哪个机器上，哪个IP上运行，内存多大</li></ul><h4 id="g" tabindex="-1"><a class="header-anchor" href="#g" aria-hidden="true">#</a> <code>g</code></h4><p><code>g</code> g存储在程序上下文中，而程序上下文会随着每一个请求的进入而激活，随着每一个请求的处理完毕而销毁，所以每次请求都会重设这个<code>g</code>值。</p><p>我们通常会使用它结合钩子来保存每个请求处理前所需要的全局变量。</p><p><code>g</code> 保存的是当前请求的全局变量，不同的请求会有不同的全局变量，通过不同的<code>thread id</code>区别。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> flask <span class="token keyword">import</span> Flask<span class="token punctuation">,</span> g

app <span class="token operator">=</span> Flask<span class="token punctuation">(</span>__name__<span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">db_query</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    user_id <span class="token operator">=</span> g<span class="token punctuation">.</span>user_id
    user_name <span class="token operator">=</span> g<span class="token punctuation">.</span>user_name
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;user_id={} user_name={}&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>user_id<span class="token punctuation">,</span> user_name<span class="token punctuation">)</span><span class="token punctuation">)</span>

<span class="token decorator annotation punctuation">@app<span class="token punctuation">.</span>route</span><span class="token punctuation">(</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">def</span> <span class="token function">get_user_profile</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    g<span class="token punctuation">.</span>user_id <span class="token operator">=</span> <span class="token number">131</span>
    g<span class="token punctuation">.</span>user_name <span class="token operator">=</span> <span class="token string">&#39;Jeremy&#39;</span>
    db_query<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">return</span> <span class="token string">&#39;hello world&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期" aria-hidden="true">#</a> 生命周期</h3><ul><li><code>current_app</code>的生命周期最长，只要当前程序实例还在运行，都不会失效。</li><li><code>Request</code>和<code>g</code>的生命周期为一次请求期间，当请求处理完成后，生命周期也就完结了</li><li><code>Session</code>就是传统意义上的<code>session</code>了。只要它还未失效（用户未关闭浏览器、没有超过设定的失效时间），那么不同的请求会共用同样的<code>session</code>。</li></ul><h2 id="手动开启上下文" tabindex="-1"><a class="header-anchor" href="#手动开启上下文" aria-hidden="true">#</a> 手动开启上下文</h2><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> flask <span class="token keyword">import</span> Flask<span class="token punctuation">,</span> current_app
 
app <span class="token operator">=</span> Flask<span class="token punctuation">(</span>__name__<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>app<span class="token punctuation">)</span>    <span class="token comment">#输出结果：&lt;Flask &#39;app&#39;&gt;</span>
app2 <span class="token operator">=</span> current_app
<span class="token keyword">print</span><span class="token punctuation">(</span>app2<span class="token punctuation">)</span>    <span class="token comment">#输出结果：竟然报了一大堆的错误</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>错误信息是这样子的：<strong>​</strong><code>RuntimeError: Working outside of application context</code></strong>。意思是说我们在应用上下文之外运行的。</p><p>同样的问题还有类似的情况：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> flask <span class="token keyword">import</span> Flask<span class="token punctuation">,</span> request

app <span class="token operator">=</span> Flask<span class="token punctuation">(</span>__name__<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>request<span class="token punctuation">.</span>args<span class="token punctuation">)</span>  <span class="token comment"># 同样报错</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>错误信息是这样子的：<strong>​</strong><code>RuntimeError: Working outside of request context</code></strong>。意思是说我们在请求上下文之外运行的。</p><blockquote><p>这究竟是咋回事?</p></blockquote><p>在flask程序未运行的情况下, 调试代码或进行测试, 同样需要使用<code>current_app</code>, <code>g</code>, <code>request</code>这些对象, 但程序未运行, 所以无法使用, 此时需要手动开启上下文。</p><h3 id="app-context" tabindex="-1"><a class="header-anchor" href="#app-context" aria-hidden="true">#</a> <code>app_context</code></h3><p><code>app_context</code>为我们提供了应用上下文环境, 允许我们在外部使用应用上下文<code>current_app</code>, <code>g</code>，可以通过<code>with</code>语句进行使用:</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> flask <span class="token keyword">import</span> Flask<span class="token punctuation">,</span> current_app

app <span class="token operator">=</span> Flask<span class="token punctuation">(</span>__name__<span class="token punctuation">)</span>
<span class="token keyword">with</span> app<span class="token punctuation">.</span>app_context<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>  <span class="token comment"># 借助with语句使用app_context创建应用上下文</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>current_app<span class="token punctuation">)</span>  <span class="token comment"># &lt;Flask &#39;app&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="request-context" tabindex="-1"><a class="header-anchor" href="#request-context" aria-hidden="true">#</a> <code>request_context</code></h3><p><code>request_context</code>为我们提供了请求上下文环境，允许我们在外部使用请求上下文<code>request</code>、<code>session</code>，可以通过with语句进行使用：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> flask <span class="token keyword">import</span> Flask<span class="token punctuation">,</span> request

app <span class="token operator">=</span> Flask<span class="token punctuation">(</span>__name__<span class="token punctuation">)</span>

environ <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token string">&#39;wsgi.version&#39;</span><span class="token punctuation">:</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token string">&#39;wsgi.input&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
    <span class="token string">&#39;REQUEST_METHOD&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;GET&#39;</span><span class="token punctuation">,</span>
    <span class="token string">&#39;PATH_INFO&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>
    <span class="token string">&#39;SERVER_NAME&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;bookandmusic server&#39;</span><span class="token punctuation">,</span>
    <span class="token string">&#39;wsgi.url_scheme&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;http&#39;</span><span class="token punctuation">,</span>
    <span class="token string">&#39;SERVER_PORT&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;80&#39;</span>
<span class="token punctuation">}</span>  <span class="token comment"># 模拟解析客户端请求之后的wsgi字典数据</span>
<span class="token keyword">with</span> app<span class="token punctuation">.</span>request_context<span class="token punctuation">(</span>environ<span class="token punctuation">)</span><span class="token punctuation">:</span>  <span class="token comment"># 借助with语句使用request_context创建请求上下文</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>request<span class="token punctuation">.</span>method<span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,45),o=[p];function c(i,l){return s(),a("div",null,o)}const u=n(t,[["render",c],["__file","上下文.html.vue"]]);export{u as default};
